1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const countLiveNeighbors = (cell: Cell, liveKeys: Set<string>): number =>
15	  neighborsOf(cell).filter((neighbor) => liveKeys.has(cellKey(neighbor))).length;
16	
17	export const nextGeneration = (cells: Cell[]): Cell[] => {
18	  const liveKeys = new Set(cells.map(cellKey));
19	  const survivors = cells.filter(
20	    (cell) => countLiveNeighbors(cell, liveKeys) >= 2
21	  );
22	  const birthCandidateKeys = new Set(
23	    cells.flatMap(neighborsOf).map(cellKey)
24	  );
25	  const births: Cell[] = [...birthCandidateKeys]
26	    .filter((key) => !liveKeys.has(key))
27	    .map((key) => key.split(",").map(Number) as Cell)
28	    .filter((cell) => countLiveNeighbors(cell, liveKeys) === 3);
29	  return [...survivors, ...births];
30	};
